     1→import { PropsIconsNameCore } from '@semparar/design-system-app';
     2→import { PropsCardTransition } from '@semparar/design-system-app/src/atomic/molecules/CardTransition/Models';
     3→import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
     4→import { moment } from '../../../services/moment';
     5→import { PointsTransaction, ProcessedExtractData } from '../../ducks/points';
     6→import { NavigationProp } from '@react-navigation/native';
     7→import { PropsRootStack } from '../../../routes/Models';
     8→import { eventSelectContent } from '~/constants/functions';
     9→
    10→type TransactionType = 'RECEIVED' | 'DEBIT' | 'EXPIRED' | 'REFUNDED';
    11→
    12→const DESCRIPTIONS = {
    13→  RECEIVED: 'Ganhos',
    14→  DEBIT: 'Usados',
    15→  EXPIRED: 'Expirados',
    16→  REFUNDED: 'Estornados',
    17→} as const;
    18→
    19→const formatDateForHeader = (dateString: string): string => {
    20→  return moment(dateString).format('DD [de] MMMM').toLowerCase();
    21→};
    22→
    23→const formatPointsValue = (amount: number, type: TransactionType): string => {
    24→  const prefix = (type === 'RECEIVED' || type === 'REFUNDED') ? '+ ' : '- ';
    25→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} pontos`;
    26→};
    27→
    28→const getDescriptionSecondary = (type: TransactionType): string => {
    29→  return DESCRIPTIONS[type] || '';
    30→};
    31→
    32→const capitalizeFirstLetter = (text: string): string => {
    33→  return text.charAt(0).toUpperCase() + text.slice(1).toLowerCase();
    34→};
    35→
    36→const transformExpiredPointsTransaction = (
    37→  transaction: PointsTransaction,
    38→): propsItemsListCardTransition => {
    39→  return {
    40→    type: 'default' as const,
    41→    bgColor: 'INTENSE_COLOR_01' as const,
    42→    titleColor: 'BRAND_COMPLEMENT_01' as const,
    43→    isSelected: false,
    44→    showIcon: false,
    45→    showRightIcon: false,
    46→    showBackgroundLeftIcon: false,
    47→    title: `${transaction.amount} pontos`,
    48→    titleType: 'paragraphXL',
    49→    value: 'Expiram em',
    50→    descriptionSecondary: formatDateForHeader(transaction.date),
    51→    descriptionSecondaryColor: 'INTENSE_COLOR_05',
    52→    descriptionSecondaryType: 'paragraphMDM',
    53→    valueColor: 'BRAND_COMPLEMENT_01',
    54→    valueType: 'paragraphMD',
    55→    description: undefined,
    56→    labelBgColor: 'BRAND_COMPLEMENT_02' as any,
    57→    showLabel: false,
    58→  };
    59→};
    60→
    61→const transformPointsTransactionToItem = (
    62→  transaction: PointsTransaction,
    63→  navigation?: NavigationProp<PropsRootStack>,
    64→): PropsCardTransition => {
    65→  const valueColor =
    66→    (transaction.type === 'RECEIVED' || transaction.type === 'REFUNDED') ? 'PLUS_COLOR_02' : 'BRAND_COMPLEMENT_01';
    67→
    68→  return {
    69→    type: 'default' as const,
    70→    bgColor: 'INTENSE_COLOR_01' as const,
    71→    titleColor: 'BRAND_COMPLEMENT_01' as const,
    72→    isSelected: true,
    73→    leftIcon:
    74→      transaction.type === 'EXPIRED'
    75→        ? 'icon-less'
    76→        : (transaction.icon as PropsIconsNameCore),
    77→    leftIconColor: 'BRAND_COMPLEMENT_01',
    78→    labelBgColor: 'BRAND_COMPLEMENT_03',
    79→    showBackgroundLeftIcon: true,
    80→    title: capitalizeFirstLetter(transaction.description),
    81→    description: undefined,
    82→    value: formatPointsValue(transaction.amount, transaction.type),
    83→    valueColor,
    84→    descriptionSecondary: getDescriptionSecondary(transaction.type),
    85→    descriptionSecondaryColor: 'INTENSE_COLOR_04',
    86→    showIcon: true,
    87→    rightIcon: 'icon-next',
    88→    showRightIcon: transaction.type !== 'EXPIRED',
    89→    onPress: navigation ? () => {
    90→      eventSelectContent({
    91→        content_type: 'cta',
    92→        content_id: 'detalhe_ponto',
    93→        location_1: 'monetizacao',
    94→        location_2: 'hub_recompensas_spmais',
    95→        location_3: 'extrato_hub_recompensas',
    96→      });
    97→      navigation.navigate('PointsDetail', { transaction });
    98→    } : undefined,
    99→  };
   100→};
   101→
   102→interface GroupedTransactions {
   103→  date: string;
   104→  items: Array<propsItemsListCardTransition>;
   105→}
   106→
   107→const groupPointsTransactionsByDate = (
   108→  transactions: PointsTransaction[],
   109→  filterToExpire = false,
   110→  navigation?: NavigationProp<PropsRootStack>,
   111→): GroupedTransactions[] => {
   112→  if (!transactions?.length) {
   113→    return [];
   114→  }
   115→
   116→  const filteredTransactions = filterToExpire
   117→    ? transactions.filter(transaction => transaction.type === 'EXPIRED')
   118→    : transactions;
   119→
   120→  const sortedTransactions = [...filteredTransactions].sort((a, b) =>
   121→    moment(b.date).diff(moment(a.date)),
   122→  );
   123→
   124→  const groupedByDate = sortedTransactions.reduce((acc, transaction) => {
   125→    const formattedDate = formatDateForHeader(transaction.date);
   126→
   127→    if (!acc[formattedDate]) {
   128→      acc[formattedDate] = [];
   129→    }
   130→
   131→    if (filterToExpire) {
   132→      acc[formattedDate].push(transformExpiredPointsTransaction(transaction));
   133→    } else {
   134→      acc[formattedDate].push(
   135→        transformPointsTransactionToItem(
   136→          transaction,
   137→          navigation,
   138→        ) as propsItemsListCardTransition,
   139→      );
   140→    }
   141→    return acc;
   142→  }, {} as Record<string, Array<propsItemsListCardTransition>>);
   143→
   144→  const sortItemsByDate = (
   145→    items: Array<propsItemsListCardTransition>,
   146→    date: string,
   147→  ) => {
   148→    return items.sort((a, b) => {
   149→      const transactionA = filteredTransactions.find(
   150→        t =>
   151→          formatDateForHeader(t.date) === date &&
   152→          transformPointsTransactionToItem(t, navigation).title === a.title,
   153→      );
   154→      const transactionB = filteredTransactions.find(
